static constexpr int LVLMOVE_ZA_PKL_SIZE = 27312;

// Parse a BinLinkerAccessor16 entry into (move, level) pairs
// Format: 2-byte id, 2-byte count, (count+1) u16 offsets, then data
// Each entry: count = byteLen/3, first count*2 bytes = u16 moves, next count bytes = levels
struct MoveLevel { uint16_t move; uint8_t level; };

inline std::vector<MoveLevel> parseLearnset(const uint8_t* pkl, int pklSize, int entryIndex) {
    std::vector<MoveLevel> result;
    if (pklSize < 4) return result;
    uint16_t entryCount;
    std::memcpy(&entryCount, pkl + 2, 2);
    if (entryIndex < 0 || entryIndex >= entryCount) return result;
    // Offset table starts at byte 4
    int ofsTableStart = 4;
    uint16_t startOfs, endOfs;
    std::memcpy(&startOfs, pkl + ofsTableStart + entryIndex * 2, 2);
    std::memcpy(&endOfs, pkl + ofsTableStart + (entryIndex + 1) * 2, 2);
    if (startOfs >= endOfs) return result; // empty entry
    int byteLen = endOfs - startOfs;
    int count = byteLen / 3;
    if (count <= 0) return result;
    const uint8_t* entryData = pkl + startOfs;
    result.reserve(count);
    for (int i = 0; i < count; i++) {
        uint16_t move;
        std::memcpy(&move, entryData + i * 2, 2);
        uint8_t level = entryData[count * 2 + i];
        result.push_back({move, level});
    }
    return result;
}

// Find the index of a move in PLUS_MOVES. Returns -1 if not found.
inline int findPlusMoveIndex(uint16_t move) {
    for (int i = 0; i < PLUS_COUNT_USED; i++) {
        if (PLUS_MOVES[i] == move) return i;
    }
    return -1;
}

